/**
 * Comment status values
 */
export type CommentStatus = "pending" | "approved" | "spam";

/**
 * A comment record as stored in the database
 */
export type Comment = {
	id: string;
	resourceId: string;
	resourceType: string;
	parentId: string | null;
	authorId: string;
	body: string;
	status: CommentStatus;
	likes: number;
	editedAt?: Date;
	createdAt: Date;
	updatedAt: Date;
};

/**
 * A like record linking an author to a comment
 */
export type CommentLike = {
	id: string;
	commentId: string;
	authorId: string;
	createdAt: Date;
};

/**
 * A comment enriched with server-resolved author info and like status.
 * All dates are ISO strings (safe for serialisation over HTTP / React Query cache).
 */
export interface SerializedComment {
	id: string;
	resourceId: string;
	resourceType: string;
	parentId: string | null;
	authorId: string;
	/** Resolved from resolveUser(authorId). Falls back to "[deleted]" when user cannot be found. */
	resolvedAuthorName: string;
	/** Resolved avatar URL or null */
	resolvedAvatarUrl: string | null;
	body: string;
	status: CommentStatus;
	/** Denormalized counter — updated atomically on toggleLike */
	likes: number;
	/** True when the currentUserId query param matches an existing commentLike row */
	isLikedByCurrentUser: boolean;
	/** ISO string set when the comment body was edited; null for unedited comments */
	editedAt: string | null;
	createdAt: string;
	updatedAt: string;
	/**
	 * Number of direct replies visible to the requesting user.
	 * Includes approved replies plus any pending replies authored by `currentUserId`.
	 * Always 0 for reply comments (non-null parentId).
	 */
	replyCount: number;
}

/**
 * Paginated list result for comments
 */
export interface CommentListResult {
	items: SerializedComment[];
	total: number;
	limit: number;
	offset: number;
}

import { z } from "zod";

export const CommentStatusSchema = z.enum(["pending", "approved", "spam"]);

// ============ Comment Schemas ============

/**
 * Schema for the POST /comments request body.
 * authorId is intentionally absent — the server resolves identity from the
 * session inside onBeforePost and injects it. Never trust authorId from the
 * client body.
 */
export const createCommentSchema = z.object({
	resourceId: z.string().min(1, "Resource ID is required"),
	resourceType: z.string().min(1, "Resource type is required"),
	parentId: z.string().optional().nullable(),
	body: z.string().min(1, "Body is required").max(10000, "Comment too long"),
});

/**
 * Internal schema used after the authorId has been resolved server-side.
 * This is what gets passed to createComment() in mutations.ts.
 */
export const createCommentInternalSchema = createCommentSchema.extend({
	authorId: z.string().min(1, "Author ID is required"),
});

export const updateCommentSchema = z.object({
	body: z.string().min(1, "Body is required").max(10000, "Comment too long"),
});

export const updateCommentStatusSchema = z.object({
	status: CommentStatusSchema,
});

// ============ Query Schemas ============

/**
 * Schema for GET /comments query parameters.
 *
 * `currentUserId` is intentionally absent — it is never accepted from the client.
 * The server always resolves the caller's identity via the `resolveCurrentUserId`
 * hook and injects it internally. Accepting it from the client would allow any
 * anonymous caller to supply an arbitrary user ID and read that user's pending
 * (pre-moderation) comments.
 */
export const CommentListQuerySchema = z.object({
	resourceId: z.string().optional(),
	resourceType: z.string().optional(),
	parentId: z.string().optional().nullable(),
	status: CommentStatusSchema.optional(),
	authorId: z.string().optional(),
	sort: z.enum(["asc", "desc"]).optional(),
	limit: z.coerce.number().int().min(1).max(100).optional(),
	offset: z.coerce.number().int().min(0).optional(),
});

/**
 * Internal params schema used by `listComments()` and the `api` factory.
 * Extends the HTTP query schema with `currentUserId`, which is always injected
 * server-side (either by the HTTP handler via `resolveCurrentUserId`, or by a
 * trusted server-side caller such as a Server Component or cron job).
 */
export const CommentListParamsSchema = CommentListQuerySchema.extend({
	currentUserId: z.string().optional(),
});

export const CommentCountQuerySchema = z.object({
	resourceId: z.string().min(1),
	resourceType: z.string().min(1),
	status: CommentStatusSchema.optional(),
});

"use client";

import { MessageSquare } from "lucide-react";
import { useCommentCount } from "@btst/stack/plugins/comments/client/hooks";

export interface CommentCountProps {
	resourceId: string;
	resourceType: string;
	/** Only count approved comments (default) */
	status?: "pending" | "approved" | "spam";
	apiBaseURL: string;
	apiBasePath: string;
	headers?: HeadersInit;
	/** Optional className for the wrapper span */
	className?: string;
}

/**
 * Lightweight badge showing the comment count for a resource.
 * Does not mount a full comment thread — suitable for post list cards.
 *
 * @example
 * ```tsx
 * <CommentCount
 *   resourceId={post.slug}
 *   resourceType="blog-post"
 *   apiBaseURL="https://example.com"
 *   apiBasePath="/api/data"
 * />
 * ```
 */
export function CommentCount({
	resourceId,
	resourceType,
	status = "approved",
	apiBaseURL,
	apiBasePath,
	headers,
	className,
}: CommentCountProps) {
	const { count, isLoading } = useCommentCount(
		{ apiBaseURL, apiBasePath, headers },
		{ resourceId, resourceType, status },
	);

	if (isLoading) {
		return (
			<span
				className={`inline-flex items-center gap-1 text-xs text-muted-foreground ${className ?? ""}`}
			>
				<MessageSquare className="h-3.5 w-3.5" />
				<span className="animate-pulse">…</span>
			</span>
		);
	}

	return (
		<span
			className={`inline-flex items-center gap-1 text-xs text-muted-foreground ${className ?? ""}`}
			data-testid="comment-count"
		>
			<MessageSquare className="h-3.5 w-3.5" />
			{count}
		</span>
	);
}

"use client";

import { useState, type ComponentType } from "react";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import {
	COMMENTS_LOCALIZATION,
	type CommentsLocalization,
} from "../localization";

export interface CommentFormProps {
	/** Current user's ID — required to post */
	authorId: string;
	/** Optional parent comment ID for replies */
	parentId?: string | null;
	/** Initial body value (for editing) */
	initialBody?: string;
	/** Label for the submit button */
	submitLabel?: string;
	/** Called when form is submitted */
	onSubmit: (body: string) => Promise<void>;
	/** Called when cancel is clicked (shows Cancel button when provided) */
	onCancel?: () => void;
	/** Custom input component — defaults to a plain Textarea */
	InputComponent?: ComponentType<{
		value: string;
		onChange: (value: string) => void;
		disabled?: boolean;
		placeholder?: string;
	}>;
	/** Localization strings */
	localization?: Partial<CommentsLocalization>;
}

export function CommentForm({
	authorId: _authorId,
	initialBody = "",
	submitLabel,
	onSubmit,
	onCancel,
	InputComponent,
	localization: localizationProp,
}: CommentFormProps) {
	const loc = { ...COMMENTS_LOCALIZATION, ...localizationProp };
	const [body, setBody] = useState(initialBody);
	const [isPending, setIsPending] = useState(false);
	const [error, setError] = useState<string | null>(null);

	const resolvedSubmitLabel = submitLabel ?? loc.COMMENTS_FORM_POST_COMMENT;

	const handleSubmit = async (e: React.FormEvent) => {
		e.preventDefault();
		if (!body.trim()) return;
		setError(null);
		setIsPending(true);
		try {
			await onSubmit(body.trim());
			setBody("");
		} catch (err) {
			setError(
				err instanceof Error ? err.message : loc.COMMENTS_FORM_SUBMIT_ERROR,
			);
		} finally {
			setIsPending(false);
		}
	};

	return (
		<form
			data-testid="comment-form"
			onSubmit={handleSubmit}
			className="flex flex-col gap-2"
		>
			{InputComponent ? (
				<InputComponent
					value={body}
					onChange={setBody}
					disabled={isPending}
					placeholder={loc.COMMENTS_FORM_PLACEHOLDER}
				/>
			) : (
				<Textarea
					value={body}
					onChange={(e) => setBody(e.target.value)}
					placeholder={loc.COMMENTS_FORM_PLACEHOLDER}
					disabled={isPending}
					rows={3}
					className="resize-none"
				/>
			)}

			{error && <p className="text-sm text-destructive">{error}</p>}

			<div className="flex gap-2 justify-end">
				{onCancel && (
					<Button
						type="button"
						variant="ghost"
						size="sm"
						onClick={onCancel}
						disabled={isPending}
					>
						{loc.COMMENTS_FORM_CANCEL}
					</Button>
				)}
				<Button type="submit" size="sm" disabled={isPending || !body.trim()}>
					{isPending ? loc.COMMENTS_FORM_POSTING : resolvedSubmitLabel}
				</Button>
			</div>
		</form>
	);
}

"use client";

import { useEffect, useState, type ComponentType } from "react";
import { WhenVisible } from "@/components/ui/when-visible";
import {
	Avatar,
	AvatarFallback,
	AvatarImage,
} from "@/components/ui/avatar";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Separator } from "@/components/ui/separator";
import {
	Heart,
	MessageSquare,
	Pencil,
	X,
	LogIn,
	ChevronDown,
	ChevronUp,
} from "lucide-react";
import { formatDistanceToNow } from "date-fns";
import type { SerializedComment } from "../../types";
import { getInitials } from "../utils";
import { CommentForm } from "./comment-form";
import {
	useComments,
	useInfiniteComments,
	usePostComment,
	useUpdateComment,
	useDeleteComment,
	useToggleLike,
} from "@btst/stack/plugins/comments/client/hooks";
import {
	COMMENTS_LOCALIZATION,
	type CommentsLocalization,
} from "../localization";
import { usePluginOverrides } from "@btst/stack/context";
import type { CommentsPluginOverrides } from "../overrides";

/** Custom input component props */
export interface CommentInputProps {
	value: string;
	onChange: (value: string) => void;
	disabled?: boolean;
	placeholder?: string;
}

/** Custom renderer component props */
export interface CommentRendererProps {
	body: string;
}

/** Override slot for custom input + renderer */
export interface CommentComponents {
	Input?: ComponentType<CommentInputProps>;
	Renderer?: ComponentType<CommentRendererProps>;
}

export interface CommentThreadProps {
	/** The resource this thread is attached to (e.g. post slug, task ID) */
	resourceId: string;
	/** Discriminates resources across plugins (e.g. "blog-post", "kanban-task") */
	resourceType: string;
	/** Base URL for API calls */
	apiBaseURL: string;
	/** Path where the API is mounted */
	apiBasePath: string;
	/** Currently authenticated user ID. Omit for read-only / unauthenticated. */
	currentUserId?: string;
	/**
	 * URL to redirect unauthenticated users to.
	 * When provided and currentUserId is absent, shows a "Please login to comment" prompt.
	 */
	loginHref?: string;
	/** Optional HTTP headers for API calls (e.g. forwarding cookies) */
	headers?: HeadersInit;
	/** Swap in custom Input / Renderer components */
	components?: CommentComponents;
	/** Optional className applied to the root wrapper */
	className?: string;
	/** Localization strings — defaults to English */
	localization?: Partial<CommentsLocalization>;
	/**
	 * Number of top-level comments to load per page.
	 * Clicking "Load more" fetches the next page. Default: 10.
	 */
	pageSize?: number;
	/**
	 * When false, the comment form and reply buttons are hidden.
	 * Overrides the global `allowPosting` from `CommentsPluginOverrides`.
	 * Defaults to true.
	 */
	allowPosting?: boolean;
	/**
	 * When false, the edit button is hidden on comment cards.
	 * Overrides the global `allowEditing` from `CommentsPluginOverrides`.
	 * Defaults to true.
	 */
	allowEditing?: boolean;
}

const DEFAULT_RENDERER: ComponentType<CommentRendererProps> = ({ body }) => (
	<p className="text-sm whitespace-pre-wrap wrap-break-word">{body}</p>
);

// ─── Comment Card ─────────────────────────────────────────────────────────────

function CommentCard({
	comment,
	currentUserId,
	apiBaseURL,
	apiBasePath,
	resourceId,
	resourceType,
	headers,
	components,
	loc,
	infiniteKey,
	onReplyClick,
	allowPosting,
	allowEditing,
}: {
	comment: SerializedComment;
	currentUserId?: string;
	apiBaseURL: string;
	apiBasePath: string;
	resourceId: string;
	resourceType: string;
	headers?: HeadersInit;
	components?: CommentComponents;
	loc: CommentsLocalization;
	/** Infinite thread query key — pass for top-level comments so like optimistic
	 *  updates target the correct InfiniteData cache entry. */
	infiniteKey?: readonly unknown[];
	onReplyClick: (parentId: string) => void;
	allowPosting: boolean;
	allowEditing: boolean;
}) {
	const [isEditing, setIsEditing] = useState(false);
	const Renderer = components?.Renderer ?? DEFAULT_RENDERER;

	const config = { apiBaseURL, apiBasePath, headers };

	const updateMutation = useUpdateComment(config);
	const deleteMutation = useDeleteComment(config);
	const toggleLikeMutation = useToggleLike(config, {
		resourceId,
		resourceType,
		parentId: comment.parentId,
		currentUserId,
		infiniteKey,
	});

	const isOwn = currentUserId && comment.authorId === currentUserId;
	const isPending = comment.status === "pending";
	const isApproved = comment.status === "approved";

	const handleEdit = async (body: string) => {
		await updateMutation.mutateAsync({ id: comment.id, body });
		setIsEditing(false);
	};

	const handleDelete = async () => {
		if (!window.confirm(loc.COMMENTS_DELETE_CONFIRM)) return;
		await deleteMutation.mutateAsync(comment.id);
	};

	const handleLike = () => {
		if (!currentUserId) return;
		toggleLikeMutation.mutate({
			commentId: comment.id,
			authorId: currentUserId,
		});
	};

	return (
		<div
			className="flex gap-3 py-3"
			data-testid="comment-card"
			data-comment-id={comment.id}
		>
			<Avatar className="h-8 w-8 shrink-0 mt-0.5">
				{comment.resolvedAvatarUrl && (
					<AvatarImage
						src={comment.resolvedAvatarUrl}
						alt={comment.resolvedAuthorName}
					/>
				)}
				<AvatarFallback className="text-xs">
					{getInitials(comment.resolvedAuthorName)}
				</AvatarFallback>
			</Avatar>

			<div className="flex-1 min-w-0">
				<div className="flex flex-wrap items-center gap-2 mb-1">
					<span className="text-sm font-medium">
						{comment.resolvedAuthorName}
					</span>
					<span className="text-xs text-muted-foreground">
						{formatDistanceToNow(new Date(comment.createdAt), {
							addSuffix: true,
						})}
					</span>
					{comment.editedAt && (
						<span className="text-xs text-muted-foreground italic">
							{loc.COMMENTS_EDITED_BADGE}
						</span>
					)}
					{isPending && isOwn && (
						<Badge
							variant="secondary"
							className="text-xs"
							data-testid="pending-badge"
						>
							{loc.COMMENTS_PENDING_BADGE}
						</Badge>
					)}
				</div>

				{isEditing ? (
					<CommentForm
						authorId={currentUserId ?? ""}
						initialBody={comment.body}
						submitLabel={loc.COMMENTS_SAVE_EDIT}
						InputComponent={components?.Input}
						localization={loc}
						onSubmit={handleEdit}
						onCancel={() => setIsEditing(false)}
					/>
				) : (
					<Renderer body={comment.body} />
				)}

				{!isEditing && (
					<div className="flex items-center gap-1 mt-2">
						{currentUserId && isApproved && (
							<Button
								variant="ghost"
								size="sm"
								className="h-7 px-2 text-xs gap-1"
								onClick={handleLike}
								aria-label={
									comment.isLikedByCurrentUser
										? loc.COMMENTS_UNLIKE_ARIA
										: loc.COMMENTS_LIKE_ARIA
								}
								data-testid="like-button"
							>
								<Heart
									className={`h-3.5 w-3.5 ${comment.isLikedByCurrentUser ? "fill-current text-red-500" : ""}`}
								/>
								{comment.likes > 0 && (
									<span data-testid="like-count">{comment.likes}</span>
								)}
							</Button>
						)}

						{allowPosting &&
							currentUserId &&
							!comment.parentId &&
							isApproved && (
								<Button
									variant="ghost"
									size="sm"
									className="h-7 px-2 text-xs"
									onClick={() => onReplyClick(comment.id)}
									data-testid="reply-button"
								>
									<MessageSquare className="h-3.5 w-3.5 mr-1" />
									{loc.COMMENTS_REPLY_BUTTON}
								</Button>
							)}

						{isOwn && (
							<>
								{allowEditing && isApproved && (
									<Button
										variant="ghost"
										size="sm"
										className="h-7 px-2 text-xs"
										onClick={() => setIsEditing(true)}
										data-testid="edit-button"
									>
										<Pencil className="h-3.5 w-3.5 mr-1" />
										{loc.COMMENTS_EDIT_BUTTON}
									</Button>
								)}
								<Button
									variant="ghost"
									size="sm"
									className="h-7 px-2 text-xs text-destructive hover:text-destructive"
									onClick={handleDelete}
									disabled={deleteMutation.isPending}
									data-testid="delete-button"
								>
									<X className="h-3.5 w-3.5 mr-1" />
									{loc.COMMENTS_DELETE_BUTTON}
								</Button>
							</>
						)}
					</div>
				)}
			</div>
		</div>
	);
}

// ─── Thread Inner (handles data) ──────────────────────────────────────────────

const DEFAULT_PAGE_SIZE = 100;
const REPLIES_PAGE_SIZE = 20;
const OPTIMISTIC_ID_PREFIX = "optimistic-";

function CommentThreadInner({
	resourceId,
	resourceType,
	apiBaseURL,
	apiBasePath,
	currentUserId,
	loginHref,
	headers,
	components,
	localization: localizationProp,
	pageSize: pageSizeProp,
	allowPosting: allowPostingProp,
	allowEditing: allowEditingProp,
}: CommentThreadProps) {
	const overrides = usePluginOverrides<
		CommentsPluginOverrides,
		Partial<CommentsPluginOverrides>
	>("comments", {});
	const pageSize =
		pageSizeProp ?? overrides.defaultCommentPageSize ?? DEFAULT_PAGE_SIZE;
	const allowPosting = allowPostingProp ?? overrides.allowPosting ?? true;
	const allowEditing = allowEditingProp ?? overrides.allowEditing ?? true;
	const loc = { ...COMMENTS_LOCALIZATION, ...localizationProp };
	const [replyingTo, setReplyingTo] = useState<string | null>(null);
	const [expandedReplies, setExpandedReplies] = useState<Set<string>>(
		new Set(),
	);
	const [replyOffsets, setReplyOffsets] = useState<Record<string, number>>({});

	const config = { apiBaseURL, apiBasePath, headers };

	const {
		comments,
		total,
		isLoading,
		loadMore,
		hasMore,
		isLoadingMore,
		queryKey: threadQueryKey,
	} = useInfiniteComments(config, {
		resourceId,
		resourceType,
		status: "approved",
		parentId: null,
		currentUserId,
		pageSize,
	});

	const postMutation = usePostComment(config, {
		resourceId,
		resourceType,
		currentUserId,
		infiniteKey: threadQueryKey,
		pageSize,
	});

	const handlePost = async (body: string) => {
		if (!currentUserId) return;
		await postMutation.mutateAsync({
			body,
			parentId: null,
		});
	};

	const handleReply = async (body: string, parentId: string) => {
		if (!currentUserId) return;
		await postMutation.mutateAsync({
			body,
			parentId,
			limit: REPLIES_PAGE_SIZE,
			offset: replyOffsets[parentId] ?? 0,
		});
		setReplyingTo(null);
		setExpandedReplies((prev) => new Set(prev).add(parentId));
	};

	return (
		<div className="space-y-1" data-testid="comment-thread">
			<div className="flex items-center gap-2 mb-4">
				<MessageSquare className="h-5 w-5 text-muted-foreground" />
				<h3 className="font-semibold text-sm">
					{total === 0 ? loc.COMMENTS_TITLE : `${total} ${loc.COMMENTS_TITLE}`}
				</h3>
			</div>

			{isLoading && (
				<div className="space-y-4">
					{[1, 2].map((i) => (
						<div key={i} className="flex gap-3 py-3 animate-pulse">
							<div className="h-8 w-8 rounded-full bg-muted shrink-0" />
							<div className="flex-1 space-y-2">
								<div className="h-3 w-24 rounded bg-muted" />
								<div className="h-3 w-full rounded bg-muted" />
								<div className="h-3 w-3/4 rounded bg-muted" />
							</div>
						</div>
					))}
				</div>
			)}

			{!isLoading && comments.length > 0 && (
				<div className="divide-y divide-border">
					{comments.map((comment) => (
						<div key={comment.id}>
							<CommentCard
								comment={comment}
								currentUserId={currentUserId}
								apiBaseURL={apiBaseURL}
								apiBasePath={apiBasePath}
								resourceId={resourceId}
								resourceType={resourceType}
								headers={headers}
								components={components}
								loc={loc}
								infiniteKey={threadQueryKey}
								onReplyClick={(parentId) => {
									setReplyingTo(replyingTo === parentId ? null : parentId);
								}}
								allowPosting={allowPosting}
								allowEditing={allowEditing}
							/>

							{/* Replies */}
							<RepliesSection
								parentId={comment.id}
								resourceId={resourceId}
								resourceType={resourceType}
								apiBaseURL={apiBaseURL}
								apiBasePath={apiBasePath}
								currentUserId={currentUserId}
								headers={headers}
								components={components}
								loc={loc}
								expanded={expandedReplies.has(comment.id)}
								replyCount={comment.replyCount}
								onToggle={() => {
									setExpandedReplies((prev) => {
										const next = new Set(prev);
										next.has(comment.id)
											? next.delete(comment.id)
											: next.add(comment.id);
										return next;
									});
								}}
								onOffsetChange={(offset) => {
									setReplyOffsets((prev) => {
										if (prev[comment.id] === offset) return prev;
										return { ...prev, [comment.id]: offset };
									});
								}}
								allowEditing={allowEditing}
							/>

							{allowPosting && replyingTo === comment.id && currentUserId && (
								<div className="pl-11 pb-3">
									<CommentForm
										authorId={currentUserId}
										parentId={comment.id}
										submitLabel={loc.COMMENTS_FORM_POST_REPLY}
										InputComponent={components?.Input}
										localization={loc}
										onSubmit={(body) => handleReply(body, comment.id)}
										onCancel={() => setReplyingTo(null)}
									/>
								</div>
							)}
						</div>
					))}
				</div>
			)}

			{!isLoading && comments.length === 0 && (
				<p className="text-sm text-muted-foreground py-4 text-center">
					{loc.COMMENTS_EMPTY}
				</p>
			)}

			{hasMore && (
				<div className="flex justify-center pt-2">
					<Button
						variant="outline"
						size="sm"
						onClick={() => loadMore()}
						disabled={isLoadingMore}
						data-testid="load-more-comments"
					>
						{isLoadingMore ? loc.COMMENTS_LOADING_MORE : loc.COMMENTS_LOAD_MORE}
					</Button>
				</div>
			)}

			{allowPosting && (
				<>
					<Separator className="my-4" />

					{currentUserId ? (
						<div data-testid="comment-form-wrapper">
							<CommentForm
								authorId={currentUserId}
								submitLabel={loc.COMMENTS_FORM_POST_COMMENT}
								InputComponent={components?.Input}
								localization={loc}
								onSubmit={handlePost}
							/>
						</div>
					) : (
						<div
							className="flex flex-col items-center gap-3 py-6 text-center border rounded-lg bg-muted/30"
							data-testid="login-prompt"
						>
							<LogIn className="h-6 w-6 text-muted-foreground" />
							<p className="text-sm text-muted-foreground">
								{loc.COMMENTS_LOGIN_PROMPT}
							</p>
							{loginHref && (
								<a
									href={loginHref}
									className="inline-flex items-center gap-1 text-sm font-medium text-primary underline underline-offset-4"
									data-testid="login-link"
								>
									{loc.COMMENTS_LOGIN_LINK}
								</a>
							)}
						</div>
					)}
				</>
			)}
		</div>
	);
}

// ─── Replies Section ───────────────────────────────────────────────────────────

function RepliesSection({
	parentId,
	resourceId,
	resourceType,
	apiBaseURL,
	apiBasePath,
	currentUserId,
	headers,
	components,
	loc,
	expanded,
	replyCount,
	onToggle,
	onOffsetChange,
	allowEditing,
}: {
	parentId: string;
	resourceId: string;
	resourceType: string;
	apiBaseURL: string;
	apiBasePath: string;
	currentUserId?: string;
	headers?: HeadersInit;
	components?: CommentComponents;
	loc: CommentsLocalization;
	expanded: boolean;
	/** Pre-computed from the parent comment — avoids an extra fetch on mount. */
	replyCount: number;
	onToggle: () => void;
	onOffsetChange: (offset: number) => void;
	allowEditing: boolean;
}) {
	const config = { apiBaseURL, apiBasePath, headers };
	const [replyOffset, setReplyOffset] = useState(0);
	const [loadedReplies, setLoadedReplies] = useState<SerializedComment[]>([]);
	// Only fetch reply bodies once the section is expanded.
	const {
		comments: repliesPage,
		total: repliesTotal,
		isFetching: isFetchingReplies,
	} = useComments(
		config,
		{
			resourceId,
			resourceType,
			parentId,
			status: "approved",
			currentUserId,
			limit: REPLIES_PAGE_SIZE,
			offset: replyOffset,
		},
		{ enabled: expanded },
	);

	useEffect(() => {
		if (expanded) {
			setReplyOffset(0);
			setLoadedReplies([]);
		}
	}, [expanded, parentId]);

	useEffect(() => {
		onOffsetChange(replyOffset);
	}, [onOffsetChange, replyOffset]);

	useEffect(() => {
		if (!expanded) return;
		setLoadedReplies((prev) => {
			const byId = new Map(prev.map((item) => [item.id, item]));
			for (const reply of repliesPage) {
				byId.set(reply.id, reply);
			}

			// Reconcile optimistic replies once the real server reply arrives with
			// a different id. Without this, both entries can persist in local state
			// until the section is collapsed and re-opened.
			const currentPageIds = new Set(repliesPage.map((reply) => reply.id));
			const currentPageRealReplies = repliesPage.filter(
				(reply) => !reply.id.startsWith(OPTIMISTIC_ID_PREFIX),
			);

			return Array.from(byId.values()).filter((reply) => {
				if (!reply.id.startsWith(OPTIMISTIC_ID_PREFIX)) return true;
				// Keep optimistic items still present in the current cache page.
				if (currentPageIds.has(reply.id)) return true;
				// Drop stale optimistic rows that have been replaced by a real reply.
				return !currentPageRealReplies.some(
					(realReply) =>
						realReply.parentId === reply.parentId &&
						realReply.authorId === reply.authorId &&
						realReply.body === reply.body,
				);
			});
		});
	}, [expanded, repliesPage]);

	// Hide when there are no known replies — but keep rendered when already
	// expanded so a freshly-posted first reply (which increments replyCount
	// only after the server responds) stays visible in the same session.
	if (replyCount === 0 && !expanded) return null;

	// Prefer the fetched count (accurate after optimistic inserts); fall back to
	// the server-provided replyCount before the fetch completes.
	const displayCount = expanded
		? loadedReplies.length || replyCount
		: replyCount;
	const effectiveReplyTotal = repliesTotal || replyCount;
	const hasMoreReplies = loadedReplies.length < effectiveReplyTotal;

	return (
		<div className="pl-11">
			{/* Toggle button — always at the top so collapse is reachable without scrolling */}
			<Button
				variant="ghost"
				size="sm"
				className="h-7 px-2 text-xs mb-1"
				onClick={onToggle}
				data-testid={expanded ? "hide-replies-button" : "show-replies-button"}
			>
				{expanded ? (
					<ChevronUp className="h-3 w-3 mr-1" />
				) : (
					<ChevronDown className="h-3 w-3 mr-1" />
				)}
				{expanded
					? loc.COMMENTS_HIDE_REPLIES
					: `${displayCount} ${displayCount === 1 ? loc.COMMENTS_REPLIES_SINGULAR : loc.COMMENTS_REPLIES_PLURAL}`}
			</Button>
			{expanded && (
				<div
					className="border-l-2 border-border pl-3 space-y-0"
					data-testid="replies-list"
				>
					{loadedReplies.map((reply) => (
						<CommentCard
							key={reply.id}
							comment={reply}
							currentUserId={currentUserId}
							apiBaseURL={apiBaseURL}
							apiBasePath={apiBasePath}
							resourceId={resourceId}
							resourceType={resourceType}
							headers={headers}
							components={components}
							loc={loc}
							onReplyClick={() => {}} // No nested replies in v1
							allowPosting={false}
							allowEditing={allowEditing}
						/>
					))}
					{hasMoreReplies && (
						<div className="py-2">
							<Button
								variant="ghost"
								size="sm"
								className="h-7 px-2 text-xs"
								onClick={() =>
									setReplyOffset((prev) => prev + REPLIES_PAGE_SIZE)
								}
								disabled={isFetchingReplies}
								data-testid="load-more-replies"
							>
								{isFetchingReplies
									? loc.COMMENTS_LOADING_MORE
									: loc.COMMENTS_LOAD_MORE}
							</Button>
						</div>
					)}
				</div>
			)}
		</div>
	);
}

// ─── Public export: lazy-mounts on scroll into view ───────────────────────────

/**
 * Embeddable threaded comment section.
 *
 * Lazy-mounts when the component scrolls into the viewport (via WhenVisible).
 * Requires `currentUserId` to allow posting; shows a "Please login" prompt otherwise.
 *
 * @example
 * ```tsx
 * <CommentThread
 *   resourceId={post.slug}
 *   resourceType="blog-post"
 *   apiBaseURL="https://example.com"
 *   apiBasePath="/api/data"
 *   currentUserId={session?.userId}
 *   loginHref="/login"
 * />
 * ```
 */
function CommentThreadSkeleton() {
	return (
		<div className="space-y-1">
			{/* Header */}
			<div className="flex items-center gap-2 mb-4">
				<div className="h-5 w-5 rounded bg-muted animate-pulse" />
				<div className="h-4 w-24 rounded bg-muted animate-pulse" />
			</div>

			{/* Comment rows */}
			{[1, 2, 3].map((i) => (
				<div key={i} className="flex gap-3 py-3">
					<div className="h-8 w-8 rounded-full bg-muted shrink-0 mt-0.5 animate-pulse" />
					<div className="flex-1 space-y-2">
						<div className="flex items-center gap-2">
							<div className="h-3 w-20 rounded bg-muted animate-pulse" />
							<div className="h-3 w-14 rounded bg-muted animate-pulse" />
						</div>
						<div className="h-3 w-full rounded bg-muted animate-pulse" />
						<div className="h-3 w-4/5 rounded bg-muted animate-pulse" />
						<div className="flex gap-1 mt-1">
							<div className="h-7 w-12 rounded bg-muted animate-pulse" />
							<div className="h-7 w-14 rounded bg-muted animate-pulse" />
						</div>
					</div>
				</div>
			))}

			{/* Separator */}
			<div className="h-px w-full bg-muted my-4" />

			{/* Textarea placeholder */}
			<div className="space-y-2">
				<div className="h-20 w-full rounded-md border bg-muted animate-pulse" />
				<div className="flex justify-end">
					<div className="h-9 w-28 rounded-md bg-muted animate-pulse" />
				</div>
			</div>
		</div>
	);
}

export function CommentThread(props: CommentThreadProps) {
	return (
		<div id="comments" className={props.className}>
			<WhenVisible fallback={<CommentThreadSkeleton />} rootMargin="300px">
				<CommentThreadInner {...props} />
			</WhenVisible>
		</div>
	);
}

"use client";

import { useState } from "react";
import {
	Table,
	TableBody,
	TableCell,
	TableHead,
	TableHeader,
	TableRow,
} from "@/components/ui/table";
import {
	Dialog,
	DialogContent,
	DialogHeader,
	DialogTitle,
} from "@/components/ui/dialog";
import {
	AlertDialog,
	AlertDialogAction,
	AlertDialogCancel,
	AlertDialogContent,
	AlertDialogDescription,
	AlertDialogFooter,
	AlertDialogHeader,
	AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Tabs, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Checkbox } from "@/components/ui/checkbox";
import {
	Avatar,
	AvatarFallback,
	AvatarImage,
} from "@/components/ui/avatar";
import { CheckCircle, ShieldOff, Trash2, Eye } from "lucide-react";
import { toast } from "sonner";
import { formatDistanceToNow } from "date-fns";
import { useRegisterPageAIContext } from "@btst/stack/plugins/ai-chat/client/context";
import type { SerializedComment, CommentStatus } from "../../../types";
import {
	useSuspenseModerationComments,
	useUpdateCommentStatus,
	useDeleteComment,
} from "@btst/stack/plugins/comments/client/hooks";
import {
	COMMENTS_LOCALIZATION,
	type CommentsLocalization,
} from "../../localization";
import { getInitials } from "../../utils";
import { Pagination } from "../shared/pagination";

interface ModerationPageProps {
	apiBaseURL: string;
	apiBasePath: string;
	headers?: HeadersInit;
	localization?: CommentsLocalization;
}

function StatusBadge({ status }: { status: CommentStatus }) {
	const variants: Record<
		CommentStatus,
		"secondary" | "default" | "destructive"
	> = {
		pending: "secondary",
		approved: "default",
		spam: "destructive",
	};
	return <Badge variant={variants[status]}>{status}</Badge>;
}

export function ModerationPage({
	apiBaseURL,
	apiBasePath,
	headers,
	localization: localizationProp,
}: ModerationPageProps) {
	const loc = { ...COMMENTS_LOCALIZATION, ...localizationProp };
	const [activeTab, setActiveTab] = useState<CommentStatus>("pending");
	const [currentPage, setCurrentPage] = useState(1);
	const [selected, setSelected] = useState<Set<string>>(new Set());
	const [viewComment, setViewComment] = useState<SerializedComment | null>(
		null,
	);
	const [deleteIds, setDeleteIds] = useState<string[]>([]);

	const config = { apiBaseURL, apiBasePath, headers };

	const { comments, total, limit, offset, totalPages, refetch } =
		useSuspenseModerationComments(config, {
			status: activeTab,
			page: currentPage,
		});

	const updateStatus = useUpdateCommentStatus(config);
	const deleteMutation = useDeleteComment(config);

	// Register AI context with pending comment previews
	useRegisterPageAIContext({
		routeName: "comments-moderation",
		pageDescription: `${total} ${activeTab} comments in the moderation queue.\n\nTop ${activeTab} comments:\n${comments
			.slice(0, 5)
			.map(
				(c) =>
					`- "${c.body.slice(0, 80)}${c.body.length > 80 ? "…" : ""}" by ${c.resolvedAuthorName} on ${c.resourceType}/${c.resourceId}`,
			)
			.join("\n")}`,
		suggestions: [
			"Approve all safe-looking comments",
			"Flag spam comments",
			"Summarize today's discussion",
		],
	});

	const toggleSelect = (id: string) => {
		setSelected((prev) => {
			const next = new Set(prev);
			next.has(id) ? next.delete(id) : next.add(id);
			return next;
		});
	};

	const toggleSelectAll = () => {
		if (selected.size === comments.length) {
			setSelected(new Set());
		} else {
			setSelected(new Set(comments.map((c) => c.id)));
		}
	};

	const handleApprove = async (id: string) => {
		try {
			await updateStatus.mutateAsync({ id, status: "approved" });
			toast.success(loc.COMMENTS_MODERATION_TOAST_APPROVED);
			await refetch();
		} catch {
			toast.error(loc.COMMENTS_MODERATION_TOAST_APPROVE_ERROR);
		}
	};

	const handleSpam = async (id: string) => {
		try {
			await updateStatus.mutateAsync({ id, status: "spam" });
			toast.success(loc.COMMENTS_MODERATION_TOAST_SPAM);
			await refetch();
		} catch {
			toast.error(loc.COMMENTS_MODERATION_TOAST_SPAM_ERROR);
		}
	};

	const handleDelete = async (ids: string[]) => {
		try {
			await Promise.all(ids.map((id) => deleteMutation.mutateAsync(id)));
			toast.success(
				ids.length === 1
					? loc.COMMENTS_MODERATION_TOAST_DELETED
					: loc.COMMENTS_MODERATION_TOAST_DELETED_PLURAL.replace(
							"{n}",
							String(ids.length),
						),
			);
			setSelected(new Set());
			setDeleteIds([]);
			await refetch();
		} catch {
			toast.error(loc.COMMENTS_MODERATION_TOAST_DELETE_ERROR);
		}
	};

	const handleBulkApprove = async () => {
		const ids = [...selected];
		try {
			await Promise.all(
				ids.map((id) => updateStatus.mutateAsync({ id, status: "approved" })),
			);
			toast.success(
				loc.COMMENTS_MODERATION_TOAST_BULK_APPROVED.replace(
					"{n}",
					String(ids.length),
				),
			);
			setSelected(new Set());
			await refetch();
		} catch {
			toast.error(loc.COMMENTS_MODERATION_TOAST_BULK_APPROVE_ERROR);
		}
	};

	return (
		<div className="w-full max-w-5xl space-y-6" data-testid="moderation-page">
			<div>
				<h1 className="text-2xl font-bold">{loc.COMMENTS_MODERATION_TITLE}</h1>
				<p className="text-muted-foreground text-sm mt-1">
					{loc.COMMENTS_MODERATION_DESCRIPTION}
				</p>
			</div>

			<Tabs
				value={activeTab}
				onValueChange={(v) => {
					setActiveTab(v as CommentStatus);
					setCurrentPage(1);
					setSelected(new Set());
				}}
			>
				<TabsList>
					<TabsTrigger value="pending" data-testid="tab-pending">
						{loc.COMMENTS_MODERATION_TAB_PENDING}
					</TabsTrigger>
					<TabsTrigger value="approved" data-testid="tab-approved">
						{loc.COMMENTS_MODERATION_TAB_APPROVED}
					</TabsTrigger>
					<TabsTrigger value="spam" data-testid="tab-spam">
						{loc.COMMENTS_MODERATION_TAB_SPAM}
					</TabsTrigger>
				</TabsList>
			</Tabs>

			{/* Bulk actions toolbar */}
			{selected.size > 0 && (
				<div className="flex items-center gap-2 p-3 bg-muted rounded-lg">
					<span className="text-sm text-muted-foreground">
						{loc.COMMENTS_MODERATION_SELECTED.replace(
							"{n}",
							String(selected.size),
						)}
					</span>
					{activeTab !== "approved" && (
						<Button
							size="sm"
							variant="outline"
							onClick={handleBulkApprove}
							disabled={updateStatus.isPending}
						>
							<CheckCircle className="h-4 w-4 mr-1" />
							{loc.COMMENTS_MODERATION_APPROVE_SELECTED}
						</Button>
					)}
					<Button
						size="sm"
						variant="outline"
						className="text-destructive border-destructive hover:bg-destructive hover:text-destructive-foreground"
						onClick={() => setDeleteIds([...selected])}
					>
						<Trash2 className="h-4 w-4 mr-1" />
						{loc.COMMENTS_MODERATION_DELETE_SELECTED}
					</Button>
				</div>
			)}

			{comments.length === 0 ? (
				<div className="flex flex-col items-center gap-2 py-16 text-muted-foreground">
					<CheckCircle className="h-8 w-8" />
					<p className="text-sm">
						{loc.COMMENTS_MODERATION_EMPTY.replace("{status}", activeTab)}
					</p>
				</div>
			) : (
				<>
					<div className="rounded-lg border">
						<Table>
							<TableHeader>
								<TableRow>
									<TableHead className="w-10">
										<Checkbox
											checked={
												selected.size === comments.length && comments.length > 0
											}
											onCheckedChange={toggleSelectAll}
											aria-label={loc.COMMENTS_MODERATION_SELECT_ALL}
										/>
									</TableHead>
									<TableHead>{loc.COMMENTS_MODERATION_COL_AUTHOR}</TableHead>
									<TableHead>{loc.COMMENTS_MODERATION_COL_COMMENT}</TableHead>
									<TableHead>{loc.COMMENTS_MODERATION_COL_RESOURCE}</TableHead>
									<TableHead>{loc.COMMENTS_MODERATION_COL_DATE}</TableHead>
									<TableHead className="w-36">
										{loc.COMMENTS_MODERATION_COL_ACTIONS}
									</TableHead>
								</TableRow>
							</TableHeader>
							<TableBody>
								{comments.map((comment) => (
									<TableRow
										key={comment.id}
										data-testid="moderation-row"
										data-comment-id={comment.id}
									>
										<TableCell>
											<Checkbox
												checked={selected.has(comment.id)}
												onCheckedChange={() => toggleSelect(comment.id)}
												aria-label={loc.COMMENTS_MODERATION_SELECT_ONE}
											/>
										</TableCell>
										<TableCell>
											<div className="flex items-center gap-2">
												<Avatar className="h-7 w-7">
													{comment.resolvedAvatarUrl && (
														<AvatarImage src={comment.resolvedAvatarUrl} />
													)}
													<AvatarFallback className="text-xs">
														{getInitials(comment.resolvedAuthorName)}
													</AvatarFallback>
												</Avatar>
												<span className="text-sm font-medium truncate max-w-[100px]">
													{comment.resolvedAuthorName}
												</span>
											</div>
										</TableCell>
										<TableCell>
											<p className="text-sm text-muted-foreground max-w-xs truncate">
												{comment.body}
											</p>
										</TableCell>
										<TableCell>
											<span className="text-xs text-muted-foreground">
												{comment.resourceType}/{comment.resourceId}
											</span>
										</TableCell>
										<TableCell className="text-xs text-muted-foreground whitespace-nowrap">
											{formatDistanceToNow(new Date(comment.createdAt), {
												addSuffix: true,
											})}
										</TableCell>
										<TableCell>
											<div className="flex items-center gap-1">
												<Button
													variant="ghost"
													size="icon"
													className="h-7 w-7"
													title={loc.COMMENTS_MODERATION_ACTION_VIEW}
													onClick={() => setViewComment(comment)}
													data-testid="view-button"
												>
													<Eye className="h-4 w-4" />
												</Button>
												{activeTab !== "approved" && (
													<Button
														variant="ghost"
														size="icon"
														className="h-7 w-7 text-green-600 hover:text-green-700"
														title={loc.COMMENTS_MODERATION_ACTION_APPROVE}
														onClick={() => handleApprove(comment.id)}
														disabled={updateStatus.isPending}
														data-testid="approve-button"
													>
														<CheckCircle className="h-4 w-4" />
													</Button>
												)}
												{activeTab !== "spam" && (
													<Button
														variant="ghost"
														size="icon"
														className="h-7 w-7 text-orange-500 hover:text-orange-600"
														title={loc.COMMENTS_MODERATION_ACTION_SPAM}
														onClick={() => handleSpam(comment.id)}
														disabled={updateStatus.isPending}
														data-testid="spam-button"
													>
														<ShieldOff className="h-4 w-4" />
													</Button>
												)}
												<Button
													variant="ghost"
													size="icon"
													className="h-7 w-7 text-destructive hover:text-destructive"
													title={loc.COMMENTS_MODERATION_ACTION_DELETE}
													onClick={() => setDeleteIds([comment.id])}
													data-testid="delete-button"
												>
													<Trash2 className="h-4 w-4" />
												</Button>
											</div>
										</TableCell>
									</TableRow>
								))}
							</TableBody>
						</Table>
					</div>
					<Pagination
						currentPage={currentPage}
						totalPages={totalPages}
						onPageChange={setCurrentPage}
						total={total}
						limit={limit}
						offset={offset}
					/>
				</>
			)}

			{/* View comment dialog */}
			<Dialog open={!!viewComment} onOpenChange={() => setViewComment(null)}>
				<DialogContent className="max-w-2xl">
					<DialogHeader>
						<DialogTitle>{loc.COMMENTS_MODERATION_DIALOG_TITLE}</DialogTitle>
					</DialogHeader>
					{viewComment && (
						<div className="space-y-4">
							<div className="flex items-center gap-3">
								<Avatar className="h-10 w-10">
									{viewComment.resolvedAvatarUrl && (
										<AvatarImage src={viewComment.resolvedAvatarUrl} />
									)}
									<AvatarFallback>
										{getInitials(viewComment.resolvedAuthorName)}
									</AvatarFallback>
								</Avatar>
								<div>
									<p className="font-medium text-sm">
										{viewComment.resolvedAuthorName}
									</p>
									<p className="text-xs text-muted-foreground">
										{new Date(viewComment.createdAt).toLocaleString()}
									</p>
								</div>
								<StatusBadge status={viewComment.status} />
							</div>

							<div className="grid grid-cols-2 gap-3 text-sm">
								<div>
									<p className="text-muted-foreground text-xs">
										{loc.COMMENTS_MODERATION_DIALOG_RESOURCE}
									</p>
									<p className="font-mono text-xs">
										{viewComment.resourceType}/{viewComment.resourceId}
									</p>
								</div>
								<div>
									<p className="text-muted-foreground text-xs">
										{loc.COMMENTS_MODERATION_DIALOG_LIKES}
									</p>
									<p>{viewComment.likes}</p>
								</div>
								{viewComment.parentId && (
									<div>
										<p className="text-muted-foreground text-xs">
											{loc.COMMENTS_MODERATION_DIALOG_REPLY_TO}
										</p>
										<p className="font-mono text-xs">{viewComment.parentId}</p>
									</div>
								)}
								{viewComment.editedAt && (
									<div>
										<p className="text-muted-foreground text-xs">
											{loc.COMMENTS_MODERATION_DIALOG_EDITED}
										</p>
										<p className="text-xs">
											{new Date(viewComment.editedAt).toLocaleString()}
										</p>
									</div>
								)}
							</div>

							<div>
								<p className="text-muted-foreground text-xs mb-1">
									{loc.COMMENTS_MODERATION_DIALOG_BODY}
								</p>
								<div className="p-3 bg-muted rounded-lg text-sm whitespace-pre-wrap break-words">
									{viewComment.body}
								</div>
							</div>

							<div className="flex justify-end gap-2">
								{viewComment.status !== "approved" && (
									<Button
										size="sm"
										onClick={async () => {
											await handleApprove(viewComment.id);
											setViewComment(null);
										}}
										disabled={updateStatus.isPending}
										data-testid="dialog-approve-button"
									>
										<CheckCircle className="h-4 w-4 mr-1" />
										{loc.COMMENTS_MODERATION_DIALOG_APPROVE}
									</Button>
								)}
								{viewComment.status !== "spam" && (
									<Button
										size="sm"
										variant="outline"
										onClick={async () => {
											await handleSpam(viewComment.id);
											setViewComment(null);
										}}
										disabled={updateStatus.isPending}
									>
										<ShieldOff className="h-4 w-4 mr-1" />
										{loc.COMMENTS_MODERATION_DIALOG_MARK_SPAM}
									</Button>
								)}
								<Button
									size="sm"
									variant="destructive"
									onClick={() => {
										setDeleteIds([viewComment.id]);
										setViewComment(null);
									}}
								>
									<Trash2 className="h-4 w-4 mr-1" />
									{loc.COMMENTS_MODERATION_DIALOG_DELETE}
								</Button>
							</div>
						</div>
					)}
				</DialogContent>
			</Dialog>

			{/* Delete confirmation dialog */}
			<AlertDialog
				open={deleteIds.length > 0}
				onOpenChange={(open) => !open && setDeleteIds([])}
			>
				<AlertDialogContent>
					<AlertDialogHeader>
						<AlertDialogTitle>
							{deleteIds.length === 1
								? loc.COMMENTS_MODERATION_DELETE_TITLE_SINGULAR
								: loc.COMMENTS_MODERATION_DELETE_TITLE_PLURAL.replace(
										"{n}",
										String(deleteIds.length),
									)}
						</AlertDialogTitle>
						<AlertDialogDescription>
							{deleteIds.length === 1
								? loc.COMMENTS_MODERATION_DELETE_DESCRIPTION_SINGULAR
								: loc.COMMENTS_MODERATION_DELETE_DESCRIPTION_PLURAL}
						</AlertDialogDescription>
					</AlertDialogHeader>
					<AlertDialogFooter>
						<AlertDialogCancel>
							{loc.COMMENTS_MODERATION_DELETE_CANCEL}
						</AlertDialogCancel>
						<AlertDialogAction
							className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
							onClick={() => handleDelete(deleteIds)}
							data-testid="confirm-delete-button"
						>
							{deleteMutation.isPending
								? loc.COMMENTS_MODERATION_DELETE_DELETING
								: loc.COMMENTS_MODERATION_DELETE_CONFIRM}
						</AlertDialogAction>
					</AlertDialogFooter>
				</AlertDialogContent>
			</AlertDialog>
		</div>
	);
}

